node -e "
const Color = await import('colorjs.io').catch(() => null);
if (Color) {
  let c = new Color.default('color(display-p3 1 0 0)');
  console.log(c.to('oklch').toString());
} else {
  // Manual conversion: display-p3 (1,0,0) -> linear light -> XYZ -> oklab -> oklch
  // display-p3 to linear
  function srgbToLinear(c) { return c <= 0.04045 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4); }
  const r = srgbToLinear(1), g = srgbToLinear(0), b = srgbToLinear(0);
  // display-p3 linear to XYZ D65
  const x = 0.4865709486482162 * r + 0.26566769316909306 * g + 0.1982172852343625 * b;
  const y = 0.2289745640697488 * r + 0.6917385218365064 * g + 0.079286914093745 * b;
  const z = 0.0000000000000000 * r + 0.04511338185890264 * g + 1.043944368900976 * b;
  // XYZ to LMS
  const l_ = 0.8189330101 * x + 0.3618667424 * y - 0.1288597137 * z;
  const m_ = 0.0329845436 * x + 0.9293118715 * y + 0.0361456387 * z;
  const s_ = 0.0482003018 * x + 0.2643662691 * y + 0.6338517070 * z;
  // cube root
  const l1 = Math.cbrt(l_), m1 = Math.cbrt(m_), s1 = Math.cbrt(s_);
  // LMS to oklab
  const L = 0.2104542553 * l1 + 0.7936177850 * m1 - 0.0040720468 * s1;
  const A = 1.9779984951 * l1 - 2.4285922050 * m1 + 0.4505937099 * s1;
  const B = 0.0259040371 * l1 + 0.7827717662 * m1 - 0.8086757660 * s1;
  // oklab to oklch
  const C = Math.sqrt(A * A + B * B);
  const H = (Math.atan2(B, A) * 180 / Math.PI + 360) % 360;
  console.log('oklch(' + L.toFixed(4) + ' ' + C.toFixed(4) + ' ' + H.toFixed(2) + ')');
}
"

