const getSiteUrl = () => {
  if (process.env.ELEVENTY_ENV === "local") {
    return "http://localhost:8080";
  }

  if (process.env.ELEVENTY_ENV === "production") {
    return process.env.CONTEXT === "production"
      ? process.env.URL
      : process.env.DEPLOY_PRIME_URL;
  }
};

export default function () {
  return {
    environment: process.env.ELEVENTY_ENV,
    year: new Date().getFullYear(),
    url: getSiteUrl(),
  };
}

content.content:
  1→import dayjs from "dayjs";
  2→import utc from "dayjs/plugin/utc.js";
  3→import timezone from "dayjs/plugin/timezone.js";
  4→import pluginRSS from "@11ty/eleventy-plugin-rss";
  5→import pluginWebc from "@11ty/eleventy-plugin-webc";
  6→
  7→dayjs.extend(utc);
  8→dayjs.extend(timezone);
  9→dayjs.tz.setDefault("America/New_York");
 10→
 11→export default function (conf) {
 12→  conf.addPlugin(pluginRSS);
 13→  conf.addPlugin(pluginWebc, {
 14→    components: "src/_components/**/*.webc",
 15→  });
 16→
 17→  conf.addFilter("groupByYear", (posts) => {
 18→    const grouped = new Map();
 19→    for (const post of posts) {
 20→      const year = dayjs(post.data.date).year();
 21→      if (!grouped.has(year)) grouped.set(year, []);
 22→      grouped.get(year).push(post);
 23→    }
 24→    return [...grouped].map(([year, posts]) => ({ year, posts }));
 25→  });
 26→
 27→  conf.addFilter("flattenBooks", (groups) => {
 28→    return groups.flatMap((group) =>
 29→      group.books.map((book) => ({ ...book, year: group.year }))
 30→    );
 31→  });
 32→
 33→  conf.addFilter("plainTextPreview", (html, max = 290) => {
 34→    const text = html
 35→      .replace(/<[^>]+>/g, "")
 36→      .replace(/\s+/g, " ")
 37→      .trim();
 38→    if (text.length <= max) return text;
 39→    const truncated = text.slice(0, max);
 40→    const lastSpace = truncated.lastIndexOf(" ");
 41→    return truncated.slice(0, lastSpace);
 42→  });
 43→
 44→  conf.addFilter("dateFormat", (dateStr, format) => {
 45→    return dayjs(dateStr).format(format);
 46→  });
 47→
 48→  conf.addFilter("getRSSDate", (dateStr) => {
 49→    // Parse the date string in UTC and set to noon
 50→    // This prevents the date from shifting to the previous day in feed readers
 51→    let date = dayjs.utc(dateStr).hour(12).toISOString().split(".");
 52→
 53→    // Remove milliseconds (RFC 3339 requirement)
 54→    date.pop();
 55→
 56→    return date.join("") + "Z";
 57→  });
 58→
 59→  conf.addPassthroughCopy("src/manifest.webmanifest");
 60→  conf.addPassthroughCopy("src/keybase.txt");
 61→  conf.addPassthroughCopy("src/robots.txt");
 62→  conf.addPassthroughCopy("src/humans.txt");
 63→  conf.addPassthroughCopy("src/llms.txt");
 64→  conf.addPassthroughCopy("src/rss.xml");
 65→  conf.addPassthroughCopy("src/.well-known");
 66→  conf.addPassthroughCopy("src/fonts");
 67→  conf.addPassthroughCopy("src/images");
 68→  conf.addPassthroughCopy("src/videos");
 69→  conf.addPassthroughCopy("src/css");
 70→  conf.addPassthroughCopy("src/js");
 71→
 72→  conf.addCollection("nowUpdates", (collections) => {
 73→    return collections
 74→      .getFilteredByTag("now-update")
 75→      .sort((a, b) => b.date - a.date)
 76→      .map((update) => {
 77→        const date = dayjs(update.data.date);
 78→        update.data.date = date.format("YYYY-MM-DD");
 79→        update.data.dateHuman = date.format("MMMM D, YYYY");
 80→        return update;
 81→      });
 82→  });
 83→
 84→  conf.addCollection("posts", (collections) => {
 85→    return collections
 86→      .getFilteredByTag("post")
 87→      .sort((a, b) => b.date - a.date)
 88→      .map((post) => {
 89→        const date = dayjs(post.data.date);
 90→        post.data.date = date.format("YYYY-MM-DD");
 91→        post.data.dateHuman = date.format("MMMM D, YYYY");
 92→        return post;
 93→      });
 94→  });
 95→
 96→  conf.addWatchTarget("src/_components/");
 97→
 98→  conf.setServerOptions({
 99→    domDiff: false,
100→  });
101→
102→  return {
103→    dir: {
104→      input: "src",
105→      output: "dist",
106→    },
107→    markdownTemplateEngine: false,
108→  };
109→}
110→

