 1→<div webc:root="override">
 2→  <svg aria-hidden="true" xmlns="http://www.w3.org/2000/svg"></svg>
 3→</div>
 4→
 5→<style webc:scoped="home-divider">
 6→  :host {
 7→    color: var(--color-accent-primary);
 8→    display: block;
 9→    height: 2rem;
10→    overflow: hidden;
11→    width: 100%;
12→  }
13→
14→  svg {
15→    display: block;
16→    height: 100%;
17→    width: 100%;
18→  }
19→</style>
20→
21→<script webc:keep>
22→  (function () {
23→    const el = document.querySelector(".home-divider");
24→    if (!el) return;
25→    const svg = el.querySelector("svg");
26→
27→    function draw() {
28→      const w = el.offsetWidth;
29→      const h = el.offsetHeight;
30→
31→      svg.setAttribute("viewBox", `0 0 ${w} ${h}`);
32→      svg.innerHTML = "";
33→
34→      const midY = h / 2;
35→      let x = 10 + Math.random() * 20;
36→
37→      while (x < w - 10) {
38→        const len = 15 + Math.random() * 60;
39→        const angle = (Math.random() - 0.5) * 2.8;
40→        const dx = Math.cos(angle) * len;
41→        const dy = Math.sin(angle) * len;
42→        const startY = midY + (Math.random() - 0.5) * h * 0.4;
43→        const endX = x + dx;
44→        const endY = startY + dy;
45→        const bent = Math.random() < 1;
46→        let d;
47→        if (bent) {
48→          const t = 0.3 + Math.random() * 0.4;
49→          const mx = x + dx * t + (Math.random() - 0.5) * 12;
50→          const my = startY + dy * t + (Math.random() - 0.5) * 12;
51→          d = `M${x} ${startY}L${mx} ${my}L${endX} ${endY}`;
52→        } else {
53→          d = `M${x} ${startY}L${endX} ${endY}`;
54→        }
55→        const path = document.createElementNS(
56→          "http://www.w3.org/2000/svg",
57→          "path",
58→        );
59→        path.setAttribute("d", d);
60→        path.setAttribute("stroke", "currentColor");
61→        path.setAttribute("stroke-width", 2 + Math.random() * 4);
62→        path.setAttribute("stroke-linecap", "butt");
63→        path.setAttribute("fill", "none");
64→        svg.appendChild(path);
65→
66→        x += 5 + Math.random() * 12;
67→      }
68→    }
69→
70→    let resizeTimer;
71→    const intervalDuration = 1000;
72→    let interval = setInterval(draw, intervalDuration);
73→
74→    window.addEventListener("resize", function () {
75→      clearTimeout(resizeTimer);
76→      clearInterval(interval);
77→      resizeTimer = setTimeout(function () {
78→        draw();
79→        interval = setInterval(draw, intervalDuration);
80→      }, 150);
81→    });
82→
83→    draw();
84→  })();
85→</script>
86→

